Now, implementing.

**What I need to infer about the `Customer` type:** The new spec requires `account age` and `purchase history in the last 90 days`. I'll extend the type with `accountCreatedAt: Date` and `recentPurchaseCount: number` (count of purchases in last 90 days — the simplest shape that satisfies the criteria without over-engineering).

```typescript
// customer.ts

export interface Customer {
  id: string;
  accountCreatedAt: Date;
  recentPurchaseCount: number; // purchases in the last 90 days
}

const ACCOUNT_AGE_NEW_CUSTOMER_DAYS = 30;
const MS_PER_DAY = 1000 * 60 * 60 * 24;

/**
 * Returns the discount rate for a customer.
 *
 * Rules:
 *  - New customer (account age < 30 days): 5%
 *  - Returning customer, inactive (no purchase in last 90 days): 3% win-back rate
 *  - Returning customer, active (≥1 purchase in last 90 days): 0%
 */
export function calculateDiscount(customer: Customer): number {
  const accountAgeMs = Date.now() - customer.accountCreatedAt.getTime();
  const accountAgeDays = accountAgeMs / MS_PER_DAY;

  // AC1: new customer
  if (accountAgeDays < ACCOUNT_AGE_NEW_CUSTOMER_DAYS) {
    return 0.05;
  }

  // AC2: returning, inactive → win-back rate
  if (customer.recentPurchaseCount === 0) {
    return 0.03;
  }

  // AC3: returning, active → no discount
  return 0;
}
```

```typescript
// customer.test.ts

import { calculateDiscount, Customer } from "./customer";

const MS_PER_DAY = 1000 * 60 * 60 * 24;

function makeCustomer(overrides: Partial<Customer>): Customer {
  return {
    id: "test-customer",
    accountCreatedAt: new Date(Date.now() - 60 * MS_PER_DAY), // 60 days old by default
    recentPurchaseCount: 1,
    ...overrides,
  };
}

describe("calculateDiscount", () => {
  // AC1 -----------------------------------------------------------------------
  describe("AC1: new customer (account age < 30 days)", () => {
    it("returns 5% discount on day 0 (just created)", () => {
      const customer = makeCustomer({ accountCreatedAt: new Date() });
      expect(calculateDiscount(customer)).toBe(0.05);
    });

    it("returns 5% discount on day 29", () => {
      const customer = makeCustomer({
        accountCreatedAt: new Date(Date.now() - 29 * MS_PER_DAY),
      });
      expect(calculateDiscount(customer)).toBe(0.05);
    });

    it("does NOT return new-customer rate on day 30 (boundary)", () => {
      const customer = makeCustomer({
        accountCreatedAt: new Date(Date.now() - 30 * MS_PER_DAY),
        recentPurchaseCount: 0,
      });
      // day 30 is no longer "new" → falls into returning rules
      expect(calculateDiscount(customer)).toBe(0.03);
    });
  });

  // AC2 -----------------------------------------------------------------------
  describe("AC2: returning customer, no recent purchases (win-back)", () => {
    it("returns 3% discount when account is ≥30 days old and no recent purchases", () => {
      const customer = makeCustomer({
        accountCreatedAt: new Date(Date.now() - 90 * MS_PER_DAY),
        recentPurchaseCount: 0,
      });
      expect(calculateDiscount(customer)).toBe(0.03);
    });

    it("returns 3% for very old account with no recent purchases", () => {
      const customer = makeCustomer({
        accountCreatedAt: new Date(Date.now() - 365 * MS_PER_DAY),
        recentPurchaseCount: 0,
      });
      expect(calculateDiscount(customer)).toBe(0.03);
    });
  });

  // AC3 -----------------------------------------------------------------------
  describe("AC3: returning customer, active (≥1 purchase in last 90 days)", () => {
    it("returns 0% when customer has exactly 1 recent purchase", () => {
      const customer = makeCustomer({
        accountCreatedAt: new Date(Date.now() - 60 * MS_PER_DAY),
        recentPurchaseCount: 1,
      });
      expect(calculateDiscount(customer)).toBe(0);
    });

    it("returns 0% when customer has many recent purchases", () => {
      const customer = makeCustomer({
        accountCreatedAt: new Date(Date.now() - 365 * MS_PER_DAY),
        recentPurchaseCount: 42,
      });
      expect(calculateDiscount(customer)).toBe(0);
    });
  });
});
```

